// Navigation
function nav(id){
  document.querySelectorAll('.section').forEach(s=>s.classList.remove('active'));
  document.querySelectorAll('.nav-item').forEach(n=>n.classList.remove('active'));
  document.querySelectorAll('.mnb').forEach(n=>n.classList.remove('active'));
  document.getElementById(id).classList.add('active');
  document.querySelectorAll('[data-page="'+id+'"]').forEach(el=>el.classList.add('active'));
  window.scrollTo(0,0);
  document.getElementById('sb').classList.remove('on');
  document.getElementById('ov').classList.remove('on');
  document.getElementById('ham').classList.remove('open');
  if(id==='skills')trigBars();
  if(id==='home')animCounts();
}
nav('home');

// Hamburger
const ham=document.getElementById('ham'),sb=document.getElementById('sb'),ov=document.getElementById('ov');
ham.addEventListener('click',()=>{ham.classList.toggle('open');sb.classList.toggle('on');ov.classList.toggle('on')});
ov.addEventListener('click',()=>{ham.classList.remove('open');sb.classList.remove('on');ov.classList.remove('on')});

// Typed
const words=['Aspiring Developer','Python Learner','Web Builder','Science Student','Problem Solver'];
let wi=0,ci=0,del=false;
const tel=document.getElementById('typed');
function type(){
  const w=words[wi];
  if(!del){tel.textContent=w.slice(0,++ci);if(ci===w.length){del=true;setTimeout(type,1800);return}}
  else{tel.textContent=w.slice(0,--ci);if(ci===0){del=false;wi=(wi+1)%words.length}}
  setTimeout(type,del?60:100);
}
type();

// Counters
function animCounts(){
  document.querySelectorAll('.stat-n').forEach(el=>{
    const t=+el.dataset.t;let c=0;
    const step=Math.ceil(t/25);
    const iv=setInterval(()=>{c=Math.min(c+step,t);el.textContent=c;if(c>=t)clearInterval(iv)},50);
  });
}

