// Contact
function sendMsg(e){
  e.preventDefault();
  const btn=e.target.querySelector('.btn-sub');
  btn.textContent='Sent! ✓';
  btn.style.background='#22c55e';
  setTimeout(()=>{btn.textContent='Send Message →';btn.style.background='';e.target.reset();},3000);
}